{% extends "base.html" %}

{% block title %}Inbox -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="inbox">
    <h1>Inbox</h1>

    <form
        method="post"
        action="/inbox"
        class="inbox-capture"
        hx-post="/inbox"
        hx-target="#inbox-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) this.reset(); this.querySelector('#inbox-title').focus();"
    >
        <label for="inbox-title">Capture</label>
        <input
            type="text"
            id="inbox-title"
            name="title"
            placeholder="What's on your mind?"
            maxlength="300"
            autocomplete="off"
            class="inbox-capture__input"
        >
        <button type="submit" class="inbox-capture__submit">Capture</button>
    </form>

    {% if items.is_empty() %}
    <div class="inbox__empty-state" id="inbox-empty-state">
        <p>Inbox zero -- nothing to process. <a href="#inbox-title">Capture something new</a> or start your <a href="/review">weekly review</a>.</p>
    </div>
    {% endif %}
    <ul class="inbox__list" role="list" id="inbox-list"{% if items.is_empty() %} hidden{% endif %}>
        {% for item in items %}
        {% include "inbox_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script>
// Hide empty state and show list when items are added via HTMX
document.getElementById('inbox-list').addEventListener('htmx:afterSwap', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length > 0) {
        list.hidden = false;
        if (emptyState) emptyState.hidden = true;
    }
});
// Show empty state when list becomes empty after HTMX delete
document.body.addEventListener('htmx:afterSettle', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

use crate::helpers::spawn_app;

/// Helper: creates a reqwest client with cookie store and no redirect following.
fn authenticated_client() -> reqwest::Client {
    reqwest::Client::builder()
        .cookie_store(true)
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap()
}

/// Helper: register a user and log them in, returning the cookie-jar client.
async fn register_and_login(address: &str, email: &str, password: &str) -> reqwest::Client {
    let client = authenticated_client();

    // Register
    let resp = client
        .post(format!("{address}/register"))
        .form(&[
            ("email", email),
            ("password", password),
            ("password_confirmation", password),
        ])
        .send()
        .await
        .expect("Failed to register");
    assert_eq!(resp.status().as_u16(), 303, "Registration should redirect");

    // Login
    let resp = client
        .post(format!("{address}/login"))
        .form(&[("email", email), ("password", password)])
        .send()
        .await
        .expect("Failed to login");
    assert_eq!(resp.status().as_u16(), 303, "Login should redirect");

    client
}

